// This single inheritance check decides whether an exception is checked:

// Is it a RuntimeException (or a subclass)?  →  UNCHECKED
// Is it an Exception but NOT a RuntimeException?  →  CHECKED
// Is it an Error?  →  unchecked, but you should never catch it

class MyCheckedException extends Exception { }         // checked
class MyUncheckedException extends RuntimeException { } // unchecked

// The keyword "Runtime" in the parent chain is the whole story.
// Everything else about how the compiler treats your exception
// flows from this one relationship.

try {
    riskyOperation();
} catch (Exception e) {
    e.getMessage();          // the human-readable message you passed in
    e.getCause();            // the underlying exception, if this one wrapped another
    e.getStackTrace();       // array of StackTraceElement — where it happened
    e.printStackTrace();     // dump the trace to stderr (avoid in production)

    // Preserve the original cause when re-throwing — never lose the root:
    throw new ServiceException("Failed to load user", e);
}

// getCause() is what lets you chain exceptions without losing the trail.
// A good stack trace tells the full story: what failed, and what caused that.

// When you call a method that throws a checked exception, you have exactly two choices.

// CHOICE 1 — Handle it here with try/catch
public String readConfig() {
    try {
        return Files.readString(Path.of("config.yml"));
    } catch (IOException e) {
        return "default-config";   // recover with a sensible fallback
    }
}

// CHOICE 2 — Declare it and let the caller deal with it
public String readConfig() throws IOException {
    return Files.readString(Path.of("config.yml"));
}

// There is no third option. If you do neither, the code will not compile:
// "unreported exception IOException; must be caught or declared to be thrown"

// IOException — file, stream, and network operations
Files.readString(path);
socket.getInputStream();

// SQLException — raw JDBC database access
connection.prepareStatement(sql).executeQuery();

// ClassNotFoundException — reflection / dynamic class loading
Class.forName("com.example.SomeClass");

// InterruptedException — a thread was interrupted while waiting
Thread.sleep(1000);
future.get();

// ParseException — parsing dates or numbers with legacy formatters
new SimpleDateFormat("yyyy-MM-dd").parse("2026-07-08");

// A checked exception can propagate up several layers,
// as long as each layer declares it.

public byte[] loadFile(String name) throws IOException {
    return Files.readAllBytes(Path.of(name));      // origin of the exception
}

public String process(String name) throws IOException {
    byte[] data = loadFile(name);                  // declares, doesn't handle
    return new String(data);
}

public void run() {
    try {
        System.out.println(process("data.txt"));   // finally handled here
    } catch (IOException e) {
        log.error("Could not process file", e);
    }
}

// The exception travels up until someone is in a position to actually recover.

// InterruptedException is checked and deserves special respect.
// Swallowing it silently is a classic senior-level red flag.

// ❌ WRONG — you've thrown away the interruption signal
try {
    Thread.sleep(1000);
} catch (InterruptedException e) {
    // ignored — the thread no longer knows it was asked to stop
}

// ✅ RIGHT — restore the interrupt flag so callers can react
try {
    Thread.sleep(1000);
} catch (InterruptedException e) {
    Thread.currentThread().interrupt();   // re-assert the flag
    throw new TaskCancelledException("Interrupted while sleeping", e);
}

// NullPointerException — you called a method on null
String name = null;
name.length();                          // 💥 NPE

// IllegalArgumentException — a method got an argument it rejects
List.of(1, 2, 3).subList(0, 10);        // 💥 out of bounds

// IllegalStateException — the object isn't in a valid state for this call
Iterator<String> it = list.iterator();
it.remove();                            // 💥 next() was never called

// IndexOutOfBoundsException — bad index into an array or list
int[] arr = {1, 2, 3};
int x = arr[5];                         // 💥

// ArithmeticException — illegal math
int result = 10 / 0;                    // 💥 division by zero

// NumberFormatException — a string that isn't a valid number
Integer.parseInt("not-a-number");       // 💥

// Unchecked exceptions are the right tool for validating preconditions.
// You throw them to fail fast when a caller breaks your method's contract.

public void transfer(Account from, Account to, BigDecimal amount) {
    // Guard clauses — reject bad input immediately and loudly
    if (from == null || to == null) {
        throw new IllegalArgumentException("Accounts must not be null");
    }
    if (amount.signum() <= 0) {
        throw new IllegalArgumentException("Amount must be positive, got: " + amount);
    }
    if (from.getBalance().compareTo(amount) < 0) {
        throw new IllegalStateException("Insufficient funds in account " + from.getId());
    }

    from.debit(amount);
    to.credit(amount);
}

// Objects.requireNonNull is the idiomatic null guard:
public UserService(UserRepository repo) {
    this.repo = Objects.requireNonNull(repo, "repo must not be null");
}

// ❌ WRONG — catching NPE hides the bug instead of fixing it
try {
    processUser(user);
} catch (NullPointerException e) {
    // "handled" — but the real problem (user is null) is still there
}

// ✅ RIGHT — prevent the null in the first place
if (user != null) {
    processUser(user);
}

// ✅ BETTER — design the null away with Optional
userRepository.findById(id)
    .ifPresent(this::processUser);

// An unchecked exception in your logs is a to-do item for a developer,
// not an event to be swallowed at runtime.

// Because nothing declares them, unchecked exceptions travel all the way up
// the call stack until something catches them — or the thread dies.

public int parse(String raw) {
    return Integer.parseInt(raw);         // may throw NumberFormatException
}

public int total(List<String> values) {
    return values.stream()
        .mapToInt(this::parse)            // no try/catch, no throws needed
        .sum();
}

// If any value is malformed, the exception bubbles up through total()
// with zero ceremony. This is powerful, but it means you must think
// carefully about WHERE the top-level safety net lives — for a web app,
// that's usually a global @ControllerAdvice handler.

// RECOVERABLE → checked feels natural (though many teams still wrap it)
// "The config file might not exist yet on first run"
public Config load() throws IOException { ... }

// PROGRAMMING ERROR → always unchecked
// "This method requires a positive amount — a negative one is a caller bug"
if (amount < 0) throw new IllegalArgumentException("amount must be >= 0");

// BUSINESS RULE VIOLATION → unchecked domain exception (modern convention)
// "User tried to withdraw more than their balance"
if (balance < amount) throw new InsufficientFundsException(accountId);

// NOT-FOUND that is EXPECTED → not an exception at all, use Optional
public Optional<User> findByEmail(String email) { ... }

// NOT-FOUND that is a BUG or an error → unchecked exception
public User getById(Long id) {
    return repo.findById(id)
        .orElseThrow(() -> new UserNotFoundException(id));
}

// Checked exceptions are not obsolete. Reach for them when ALL of these hold:

// 1. The failure is genuinely recoverable by the immediate caller.
// 2. Recovery requires a specific, deliberate action — not just logging.
// 3. You want the compiler to guarantee the caller cannot forget.

// Classic legitimate example: a payment gateway with retryable failures
public class PaymentDeclinedException extends Exception {
    private final String reasonCode;
    // The caller MUST decide: retry with another card, or cancel the order.
    // Silently ignoring this would be a serious defect — so make it checked.
}

// Rule of thumb: if forgetting to handle it would be a costly mistake,
// and handling it is a real option, checked exceptions add real value.
// Otherwise, prefer unchecked.

try {
    // code that might throw
    riskyOperation();
} catch (SpecificException e) {
    // runs only if SpecificException (or a subclass) was thrown
    handleIt(e);
} finally {
    // ALWAYS runs — exception or not, return or not
    cleanup();
}

// finally runs even if the try block returns, and even if the catch
// block throws again. It is the guaranteed cleanup hook — but for
// resources, try-with-resources (below) is almost always better.

// Catch blocks are evaluated top to bottom. Order from specific to general,
// or the broad catch will shadow the specific ones.

// ❌ WRONG — Exception catches everything, FileNotFoundException is unreachable
try {
    read();
} catch (Exception e) {          // compile error: already caught above? no —
    ...                          // this swallows FileNotFoundException too
} catch (FileNotFoundException e) {
    ...                          // unreachable
}

// ✅ RIGHT — narrowest type first
try {
    read();
} catch (FileNotFoundException e) {
    createDefaultFile();         // specific, meaningful recovery
} catch (IOException e) {
    log.error("I/O failed", e);  // broader fallback
}

// When two exception types need identical handling, combine them with |
// (Java 7+). This removes duplicated catch bodies.

try {
    Class<?> clazz = Class.forName(className);
    Object instance = clazz.getDeclaredConstructor().newInstance();
} catch (ClassNotFoundException | NoSuchMethodException |
         InstantiationException | IllegalAccessException e) {
    throw new PluginLoadException("Could not load plugin: " + className, e);
}

// The caught variable e is effectively final and typed as the closest
// common supertype of the listed exceptions.

// Any object implementing AutoCloseable can be declared in the try header.
// It is closed automatically, in reverse order, even if an exception is thrown.

// ❌ OLD WAY — verbose, error-prone, easy to leak
BufferedReader reader = null;
try {
    reader = new BufferedReader(new FileReader("data.txt"));
    return reader.readLine();
} finally {
    if (reader != null) reader.close();   // must remember; can itself throw
}

// ✅ MODERN WAY — the resource is closed for you, guaranteed
try (BufferedReader reader = new BufferedReader(new FileReader("data.txt"))) {
    return reader.readLine();
}   // reader.close() is called automatically here

// Multiple resources close in reverse declaration order:
try (Connection conn = dataSource.getConnection();
     PreparedStatement ps = conn.prepareStatement(sql)) {
    return ps.executeQuery();
}

// A low-level exception should not leak into a high-level API.
// Translate it into a meaningful exception for your layer — and ALWAYS
// pass the original as the cause so the stack trace stays intact.

public User findUser(Long id) {
    try {
        return jdbcTemplate.queryForObject(SQL, userMapper, id);
    } catch (SQLException e) {
        // Don't leak SQLException to the service layer. Translate it.
        throw new DataAccessException("Failed to load user " + id, e);
        //                                                          ^ keep the cause!
    }
}

// ❌ throw new DataAccessException("Failed");        // loses the root cause
// ✅ throw new DataAccessException("Failed", e);     // preserves the trail

// A return inside finally overrides everything — even a thrown exception.
// This is a notorious source of silently swallowed bugs. Never do it.

// ❌ NEVER — the finally return eats the exception entirely
public int broken() {
    try {
        throw new RuntimeException("boom");
    } finally {
        return 42;   // the exception vanishes; caller sees 42, no error
    }
}

// Rule: finally is for CLEANUP only. Never return or throw from it.

// Extend RuntimeException for a domain exception (the modern default).
public class UserNotFoundException extends RuntimeException {

    private final Long userId;

    public UserNotFoundException(Long userId) {
        super("User not found with id: " + userId);   // helpful message
        this.userId = userId;                          // structured context
    }

    public Long getUserId() {
        return userId;   // callers/handlers can use this without parsing the message
    }
}

// Usage reads like the business rule it enforces:
User user = userRepository.findById(id)
    .orElseThrow(() -> new UserNotFoundException(id));

// A robust custom exception mirrors Throwable's constructors so it can
// always wrap an underlying cause. Omitting the (String, Throwable) form
// is a common mistake that leads to lost stack traces.

public class PaymentProcessingException extends RuntimeException {

    public PaymentProcessingException(String message) {
        super(message);
    }

    public PaymentProcessingException(String message, Throwable cause) {
        super(message, cause);        // preserve the original failure
    }

    public PaymentProcessingException(Throwable cause) {
        super(cause);
    }
}

// Now you can wrap cleanly:
try {
    gateway.charge(card, amount);
} catch (GatewayTimeoutException e) {
    throw new PaymentProcessingException("Charge failed for order " + orderId, e);
}

// Give your application a common base exception. Callers can then catch
// broadly (all domain errors) or narrowly (one specific case).

public abstract class DomainException extends RuntimeException {
    protected DomainException(String message) { super(message); }
    protected DomainException(String message, Throwable cause) { super(message, cause); }
}

public class UserNotFoundException extends DomainException {
    public UserNotFoundException(Long id) { super("User not found: " + id); }
}

public class DuplicateEmailException extends DomainException {
    public DuplicateEmailException(String email) { super("Email already registered: " + email); }
}

// A handler can now catch the whole family in one place:
// catch (DomainException e) { ... map to a 4xx response ... }

// If (and only if) the caller MUST be forced to handle recovery,
// extend Exception instead of RuntimeException.

public class QuotaExceededException extends Exception {

    private final int retryAfterSeconds;

    public QuotaExceededException(int retryAfterSeconds) {
        super("Quota exceeded. Retry after " + retryAfterSeconds + "s");
        this.retryAfterSeconds = retryAfterSeconds;
    }

    public int getRetryAfterSeconds() { return retryAfterSeconds; }
}

// The checked type guarantees no caller can forget to decide:
// wait and retry, or surface a 429 to the client.
public void submit(Job job) throws QuotaExceededException { ... }

// The single most damaging exception anti-pattern: an empty catch block.
// It converts a loud, traceable failure into a silent, invisible bug.

// ❌ CRIMINAL — the failure disappears without a trace
try {
    updatePayment();
} catch (Exception e) {
    // nothing here
}

// ❌ BARELY BETTER — printStackTrace is not logging; it's noise on stderr
try {
    updatePayment();
} catch (Exception e) {
    e.printStackTrace();
}

// ✅ RIGHT — log with context, then handle or re-throw
try {
    updatePayment();
} catch (PaymentException e) {
    log.error("Payment update failed for order {}", orderId, e);
    throw new OrderProcessingException("Could not update payment", e);
}

// Catching Exception (or worse, Throwable) is a blunt instrument.
// It hides bugs and can even swallow things you never meant to handle.

// ❌ TOO BROAD — this also catches NPEs and other programming bugs,
//    masking them as if they were expected I/O failures
try {
    return readAndParse(file);
} catch (Exception e) {
    return defaultValue;
}

// ✅ PRECISE — handle only what you actually anticipate
try {
    return readAndParse(file);
} catch (IOException e) {
    return defaultValue;         // expected: file might be unreadable
}
// A NullPointerException here would (correctly) propagate as the bug it is.

// NEVER catch Throwable — it includes Error (OutOfMemoryError, etc.),
// which you cannot and should not try to recover from.

// Detect bad state as early as possible, at the edge of your system,
// with a clear unchecked exception. The deeper a bad value travels,
// the harder the eventual failure is to diagnose.

public Order createOrder(OrderRequest req) {
    Objects.requireNonNull(req, "request must not be null");
    if (req.items().isEmpty()) {
        throw new IllegalArgumentException("Order must contain at least one item");
    }
    if (req.total().signum() <= 0) {
        throw new IllegalArgumentException("Order total must be positive");
    }
    // From here down, every downstream method can trust its inputs.
    return orderRepository.save(Order.from(req));
}

// A good exception message includes WHAT failed and the RELEVANT VALUES.
// You are writing for a stressed engineer reading a log, not a compiler.

// ❌ USELESS
throw new IllegalArgumentException("Invalid input");
throw new IllegalStateException("Error");

// ✅ ACTIONABLE — states the rule and the offending value
throw new IllegalArgumentException(
    "Discount must be between 0 and 100, but was: " + discount);

throw new IllegalStateException(
    "Cannot ship order " + orderId + " in status " + status +
    "; expected status PAID");

// Never put secrets (passwords, tokens, full card numbers) in a message —
// exception messages end up in logs.

// Exceptions are for exceptional conditions, not for normal branching.
// They are expensive (stack trace capture) and obscure the logic.

// ❌ WRONG — using an exception as an if/else
try {
    return cache.get(key);         // throws if the key is absent
} catch (NotFoundException e) {
    return loadAndCache(key);
}

// ✅ RIGHT — check the normal case with a normal branch
return cache.containsKey(key)
    ? cache.get(key)
    : loadAndCache(key);

// If "not found" is an expected, routine outcome, model it with
// Optional or a boolean — not with an exception.

// Prefer AutoCloseable + try-with-resources over manual finally cleanup.
// It is shorter, cannot leak, and correctly handles the tricky case where
// close() itself throws (it becomes a "suppressed" exception, not a lost one).

try (var conn = pool.getConnection();
     var stmt = conn.prepareStatement(sql)) {
    stmt.executeUpdate();
}   // both closed automatically, in reverse order, no leaks

// If close() throws while the body was also throwing, the body's exception
// wins and close()'s is attached via getSuppressed() — nothing is lost.

// One class handles errors for your entire application. Each @ExceptionHandler
// maps an exception type to a consistent HTTP response.

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(UserNotFoundException.class)
    public ResponseEntity<ApiError> handleNotFound(UserNotFoundException e) {
        var error = new ApiError(404, "NOT_FOUND", e.getMessage());
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ApiError> handleBadRequest(IllegalArgumentException e) {
        var error = new ApiError(400, "BAD_REQUEST", e.getMessage());
        return ResponseEntity.badRequest().body(error);
    }

    // Catch-all — never leak a stack trace to the client
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ApiError> handleUnexpected(Exception e) {
        log.error("Unexpected error", e);
        var error = new ApiError(500, "INTERNAL_ERROR", "Something went wrong");
        return ResponseEntity.internalServerError().body(error);
    }
}

// The clean flow: repository/service throws a meaningful domain exception,
// the controller stays oblivious, and the advice maps it to a status code.

@Service
public class UserService {
    public UserDTO getById(Long id) {
        return userRepository.findById(id)
            .map(mapper::toDTO)
            .orElseThrow(() -> new UserNotFoundException(id));   // just throw
    }
}

@RestController
@RequestMapping("/users")
public class UserController {
    @GetMapping("/{id}")
    public UserDTO get(@PathVariable Long id) {
        return userService.getById(id);   // no try/catch — advice handles it
    }
}

// The controller reads like the happy path. Error mapping lives in one place.

// For simple cases you can annotate the exception itself, skipping the
// handler method entirely. Spring reads the status when it propagates.

@ResponseStatus(HttpStatus.NOT_FOUND)
public class UserNotFoundException extends RuntimeException {
    public UserNotFoundException(Long id) {
        super("User not found: " + id);
    }
}

// Or throw ResponseStatusException inline for one-off cases:
throw new ResponseStatusException(HttpStatus.NOT_FOUND, "User not found: " + id);

// Use @RestControllerAdvice when you need a consistent error BODY;
// use @ResponseStatus for quick status-only mapping.

// @Valid on a DTO triggers MethodArgumentNotValidException on bad input.
// Handle it once to return field-level errors in your standard shape.

@ExceptionHandler(MethodArgumentNotValidException.class)
public ResponseEntity<ApiError> handleValidation(MethodArgumentNotValidException e) {
    Map<String, String> fieldErrors = e.getBindingResult().getFieldErrors().stream()
        .collect(Collectors.toMap(
            FieldError::getField,
            fe -> fe.getDefaultMessage() == null ? "invalid" : fe.getDefaultMessage(),
            (a, b) -> a));

    var error = new ApiError(400, "VALIDATION_FAILED", "Request validation failed");
    error.setFieldErrors(fieldErrors);
    return ResponseEntity.badRequest().body(error);
}

// Result: every client, for every endpoint, gets the SAME { status, code,
// message, fieldErrors } contract — the hallmark of a well-built API.
